'use client';

import { useState, useMemo } from 'react';
import { motion } from 'framer-motion';
import { Search, Trash2, ExternalLink, Eye } from 'lucide-react';
import { mockArticles } from '@/data/articles';
import { mockTopics } from '@/data/topics';
import { formatDate, formatNumber } from '@/lib/utils';
import Link from 'next/link';

export default function AdminArticlesPage() {
  const [search, setSearch] = useState('');
  const [topicFilter, setTopicFilter] = useState('all');
  const [articles, setArticles] = useState(mockArticles);

  const filtered = useMemo(() => {
    return articles.filter((article) => {
      const matchSearch =
        article.title.toLowerCase().includes(search.toLowerCase()) ||
        article.author.name.toLowerCase().includes(search.toLowerCase());
      const matchTopic = topicFilter === 'all' || article.topic.slug === topicFilter;
      return matchSearch && matchTopic;
    });
  }, [articles, search, topicFilter]);

  const handleDelete = (id: string) => {
    if (window.confirm('Bạn có chắc muốn xóa bài viết này?')) {
      setArticles((prev) => prev.filter((a) => a.id !== id));
    }
  };

  return (
    <div className="p-6 max-w-6xl mx-auto">
      <div className="mb-6">
        <h1 className="text-2xl font-bold" style={{ color: '#E7E9EA' }}>Quản lý Bài viết</h1>
        <p className="text-sm mt-1" style={{ color: '#71767B' }}>{articles.length} bài viết</p>
      </div>

      {/* Filters */}
      <div className="flex flex-wrap gap-3 mb-6">
        <div className="relative flex-1 min-w-[200px]">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4" style={{ color: '#71767B' }} />
          <input
            type="text"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            placeholder="Tìm bài viết hoặc tác giả..."
            className="w-full pl-10 pr-4 py-2 rounded-xl border text-sm focus:outline-none"
            style={{ background: '#16181C', borderColor: '#2F3336', color: '#E7E9EA' }}
            onFocus={(e) => (e.target.style.borderColor = '#8B5CF6')}
            onBlur={(e) => (e.target.style.borderColor = '#2F3336')}
          />
        </div>
        <select
          value={topicFilter}
          onChange={(e) => setTopicFilter(e.target.value)}
          className="px-3 py-2 rounded-xl border text-sm focus:outline-none"
          style={{ background: '#16181C', borderColor: '#2F3336', color: '#E7E9EA' }}
        >
          <option value="all">Tất cả chủ đề</option>
          {mockTopics.map((topic) => (
            <option key={topic.slug} value={topic.slug}>
              {topic.icon} {topic.name}
            </option>
          ))}
        </select>
      </div>

      {/* Table */}
      <div className="rounded-2xl border overflow-hidden" style={{ background: '#16181C', borderColor: '#2F3336' }}>
        <div className="overflow-x-auto">
          <table className="w-full">
            <thead>
              <tr style={{ borderBottom: '1px solid #2F3336' }}>
                <th className="text-left py-3 px-4 text-xs font-medium" style={{ color: '#71767B' }}>Bài viết</th>
                <th className="text-left py-3 px-4 text-xs font-medium" style={{ color: '#71767B' }}>Tác giả</th>
                <th className="text-left py-3 px-4 text-xs font-medium" style={{ color: '#71767B' }}>Chủ đề</th>
                <th className="text-right py-3 px-4 text-xs font-medium" style={{ color: '#71767B' }}>❤️</th>
                <th className="text-right py-3 px-4 text-xs font-medium" style={{ color: '#71767B' }}>💬</th>
                <th className="text-left py-3 px-4 text-xs font-medium" style={{ color: '#71767B' }}>Ngày đăng</th>
                <th className="text-right py-3 px-4 text-xs font-medium" style={{ color: '#71767B' }}>Actions</th>
              </tr>
            </thead>
            <tbody>
              {filtered.map((article, i) => (
                <motion.tr
                  key={article.id}
                  initial={{ opacity: 0, x: -10 }}
                  animate={{ opacity: 1, x: 0 }}
                  transition={{ delay: i * 0.03 }}
                  style={{ borderBottom: '1px solid #2F3336' }}
                  className="transition-colors"
                  onMouseEnter={(e) => (e.currentTarget.style.backgroundColor = 'rgba(255,255,255,0.02)')}
                  onMouseLeave={(e) => (e.currentTarget.style.backgroundColor = 'transparent')}
                >
                  <td className="py-3 px-4">
                    <p className="text-sm font-medium truncate max-w-[280px]" style={{ color: '#E7E9EA' }}>{article.title}</p>
                  </td>
                  <td className="py-3 px-4">
                    <div className="flex items-center gap-2">
                      <img src={article.author.avatar} alt="" className="w-6 h-6 rounded-full" style={{ background: '#2F3336' }} />
                      <span className="text-sm" style={{ color: '#71767B' }}>{article.author.name}</span>
                    </div>
                  </td>
                  <td className="py-3 px-4">
                    <span className="text-xs px-2 py-0.5 rounded-full" style={{ background: `${article.topic.color}20`, color: article.topic.color }}>
                      {article.topic.icon} {article.topic.name}
                    </span>
                  </td>
                  <td className="py-3 px-4 text-sm text-right" style={{ color: '#F91880' }}>{formatNumber(article.likesCount)}</td>
                  <td className="py-3 px-4 text-sm text-right" style={{ color: '#3B82F6' }}>{formatNumber(article.commentsCount)}</td>
                  <td className="py-3 px-4 text-sm" style={{ color: '#71767B' }}>{formatDate(article.createdAt)}</td>
                  <td className="py-3 px-4">
                    <div className="flex items-center justify-end gap-1">
                      <Link href={`/article/${article.id}`}>
                        <button className="p-1.5 rounded-lg transition-colors hover:bg-white/5" style={{ color: '#71767B' }} title="Xem">
                          <Eye className="w-4 h-4" />
                        </button>
                      </Link>
                      <button
                        onClick={() => handleDelete(article.id)}
                        className="p-1.5 rounded-lg transition-colors hover:bg-red-500/10"
                        style={{ color: '#EF4444' }}
                        title="Xóa"
                      >
                        <Trash2 className="w-4 h-4" />
                      </button>
                    </div>
                  </td>
                </motion.tr>
              ))}
            </tbody>
          </table>
        </div>

        {filtered.length === 0 && (
          <div className="py-12 text-center" style={{ color: '#71767B' }}>
            <p>Không tìm thấy bài viết nào</p>
          </div>
        )}
      </div>
    </div>
  );
}
